import React from 'react'

export default function (props) {
  return (
    <div>
    <h2> round number: {(props.roundNumber+1) + "/" + ((props.totalCards / 2))}</h2>
    <h3>{props.playerName + "'s score: " + props.pScore + "-VS-" + "Computer's score: " + props.cScore}</h3>
    <h4>Computer:</h4>
    {props.sendImg(props.cImg)}
    <h4>{props.playerName}:</h4>
    {props.sendImg(props.pImg)}<br></br>
    {props.buttons()}
</div>
)
}
